import{_ as r,o as t,c as i,a2 as o}from"./chunks/framework.D2pTuMig.js";const m=JSON.parse('{"title":"Démarrage Rapide — Distributeurs","description":"","frontmatter":{"title":"Démarrage Rapide — Distributeurs"},"headers":[],"relativePath":"docs/fr/publishers/onboarding-quick-start.md","filePath":"docs/fr/publishers/onboarding-quick-start.md"}'),s={name:"docs/fr/publishers/onboarding-quick-start.md"};function a(n,e,l,p,u,d){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="demarrage-rapide-—-distributeurs" tabindex="-1">Démarrage Rapide — Distributeurs <a class="header-anchor" href="#demarrage-rapide-—-distributeurs" aria-label="Permalink to &quot;Démarrage Rapide — Distributeurs&quot;">​</a></h1><p>Vous venez de rejoindre getinside. En 3 étapes (10 minutes), votre profil est prêt à recevoir vos premières campagnes.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>Ce guide est pour vous si :</strong> vous avez reçu l&#39;email d&#39;invitation getinside et souhaitez démarrer rapidement.</p></div><hr><h2 id="etape-1-—-activez-votre-acces-2-min" tabindex="-1">Étape 1 — Activez votre accès (2 min) <a class="header-anchor" href="#etape-1-—-activez-votre-acces-2-min" aria-label="Permalink to &quot;Étape 1 — Activez votre accès (2 min)&quot;">​</a></h2><ol><li>Ouvrez l&#39;<strong>email d&#39;invitation</strong> reçu de getinside</li><li>Cliquez sur le lien d&#39;activation</li><li>Définissez votre mot de passe</li><li>Connectez-vous sur <a href="https://app.getinside.media/" target="_blank" rel="noreferrer">app.getinside.media</a></li></ol><blockquote><p>Votre compte a été créé par l&#39;équipe getinside lors de votre démo. Si vous n&#39;avez pas reçu l&#39;email, vérifiez vos spams ou contactez votre gestionnaire.</p></blockquote><hr><h2 id="etape-2-—-configurez-votre-profil-logistique-5-min" tabindex="-1">Étape 2 — Configurez votre profil logistique (5 min) <a class="header-anchor" href="#etape-2-—-configurez-votre-profil-logistique-5-min" aria-label="Permalink to &quot;Étape 2 — Configurez votre profil logistique (5 min)&quot;">​</a></h2><p>Avant de recevoir des campagnes, l&#39;algorithme a besoin de deux informations :</p><p><strong>Espace :</strong> Paramètres → Logistique</p><table tabindex="0"><thead><tr><th>Champ</th><th>Quoi renseigner</th></tr></thead><tbody><tr><td><strong>Adresse entrepôt</strong></td><td>L&#39;adresse où les supports physiques (cartons, flyers) seront livrés</td></tr><tr><td><strong>Lead Time</strong></td><td>Le délai minimum entre réception et début de distribution (ex: 3 jours)</td></tr></tbody></table><blockquote><p>Ces données permettent à la plateforme de vous proposer uniquement des campagnes que vous pouvez honorer selon vos contraintes réelles.</p></blockquote><hr><h2 id="etape-3-—-creez-votre-premiere-audience-3-min" tabindex="-1">Étape 3 — Créez votre première audience (3 min) <a class="header-anchor" href="#etape-3-—-creez-votre-premiere-audience-3-min" aria-label="Permalink to &quot;Étape 3 — Créez votre première audience (3 min)&quot;">​</a></h2><p>Votre audience, c&#39;est ce que vous vendez aux annonceurs. Plus elle est précise, plus vous recevez de campagnes pertinentes.</p><p><strong>Espace :</strong> Monétisation → Créer une audience</p><p>Renseignez au minimum :</p><ul><li><strong>Nom de l&#39;audience</strong> : ex. &quot;Clients e-commerce mode femme 25-45 ans&quot;</li><li><strong>Panier moyen</strong> de vos clients</li><li><strong>Catégorie</strong> de vos produits</li><li><strong>Volume hebdomadaire</strong> de colis (pour l&#39;Insertion Colis)</li></ul><blockquote><p>Une fiche audience complète et précise est le principal facteur d&#39;attractivité auprès des annonceurs. Prenez le temps de bien la remplir.</p></blockquote><hr><h2 id="vous-etes-pret-✅" tabindex="-1">Vous êtes prêt ✅ <a class="header-anchor" href="#vous-etes-pret-✅" aria-label="Permalink to &quot;Vous êtes prêt ✅&quot;">​</a></h2><p>Un <strong>appel de validation</strong> avec l&#39;équipe getinside confirme votre mise en ligne sur la marketplace. Dès lors, vous recevrez des <strong>propositions de campagnes</strong> directement sur la plateforme.</p><p><strong>Règle d&#39;or à retenir :</strong> Vous avez <strong>48h ouvrées</strong> pour répondre à chaque proposition. Au-delà, elle expire et peut impacter votre <a href="/handbook/docs/fr/publishers/score-distributor.html">Score Distributeur</a>.</p><hr><p><strong>Prochaines étapes :</strong></p><ul><li><a href="/handbook/docs/fr/publishers/onboarding-process.html">Processus complet d&#39;onboarding</a> — le fonctionnement détaillé</li><li><a href="/handbook/docs/fr/publishers/score-distributor.html">Score Distributeur</a> — comment maximiser votre visibilité</li><li><a href="/handbook/docs/fr/publishers/payouts.html">Paiements &amp; Wallet</a> — comprendre quand et comment vous serez payé</li></ul>',27)])])}const g=r(s,[["render",a]]);export{m as __pageData,g as default};
